const base = 'https://cdn.jsdelivr.net/gh/yewang/besogo@4f03a3a04bc632c49ca9b494cbcad5c7cfb3f6b2/';
for (const p of ['css/besogo.css','css/board-flat.css']) { const l = document.createElement('link'); l.rel = 'stylesheet'; l.href = base + p; document.head.appendChild(l); }
const files = ['besogo','boardDisplay','commentPanel','controlPanel','coord','editor','filePanel','gameRoot','loadSgf','namesPanel','parseSgf','saveSgf','svgUtil','toolPanel','treePanel'];
for (const f of files) await new Promise((ok,bad) => { const s = document.createElement('script'); s.src = base + 'js/' + f + '.js'; s.onload = ok; s.onerror = bad; document.head.appendChild(s); });
const el = document.getElementById('besogo'); el.style.height = '620px';
window.besogo.create(el, { sgf: data.sgf, panels: 'control+names+comment+tree', resize: 'fixed', coord: 'western', nowheel: true });

